mapper.select:
SELECT trainerName, memberName, assignedAt, membershipName, remainingCount, status FROM ( SELECT tu.name AS trainerName, mu.name AS memberName, mp.register_date AS assignedAt, CONCAT('PT ', IFNULL(ms.type_rep, 0), '회') AS membershipName, IFNULL(mp.lesson_count, 0) AS remainingCount, CASE WHEN mp.status = 'active' THEN '이용중' ELSE '종료' END AS status FROM MEMBERSHIP_PT mp JOIN TRAINER t ON mp.trainer_id = t.id JOIN `USER` tu ON t.user_id = tu.id JOIN MEMBER m ON mp.member_id = m.id JOIN `USER` mu ON m.user_id = mu.id LEFT JOIN MEMBERSHIP ms ON mp.membership_id = ms.id WHERE t.gym_id = #{value}
UNION ALL
SELECT tu.name AS trainerName, mu.name AS memberName, l.created_at AS assignedAt, 'PT 예약회원' AS membershipName, 0 AS remainingCount, '예약회원' AS status FROM LESSON l JOIN TRAINER t ON l.trainer_id = t.id JOIN `USER` tu ON t.user_id = tu.id JOIN MEMBER m ON l.client_id = m.id JOIN `USER` mu ON m.user_id = mu.id WHERE t.gym_id = #{value} AND l.status != '취소' AND NOT EXISTS ( SELECT 1 FROM MEMBERSHIP_PT mp WHERE mp.member_id = l.client_id AND mp.trainer_id = l.trainer_id ) ) x ORDER BY assignedAt DESC
